{"command": "# Check for new config options we're missing
curl -s "https://raw.githubusercontent.com/NousResearch/hermes-agent/main/hermes_cli/config.py" | python3 -c "
import sys
lines = sys.stdin.read().split('\n')
# Find DEFAULT_CONFIG
in_config = False
for i,line in enumerate(lines):
    if 'DEFAULT_CONFIG' in line and '{' in line:
        in_config = True
    if in_config:
        print(f'{i}: {line}')
        if '}' in line and i > 10:
            # reached end
            pass
" 2>&1 | head -40", "timeout": 15}

{"command": "# Check recent docs site for new features
curl -s "https://hermes-agent.nousresearch.com/docs/reference/cli-commands" 2>/dev/null | python3 -c "
import sys
text = sys.stdin.read()
# Extract section headers
import re
for m in re.finditer(r'<h2[^>]*>(.*?)</h2>', text):
    print(f'Section: {m.group(1)}')
for m in re.finditer(r'<h3[^>]*>(.*?)</h3>', text):
    title = m.group(1).strip()
    if 'new' in title.lower() or 'plugin' in title.lower() or 'feature' in title.lower():
        print(f'  New: {title}')
" 2>&1 | head -30", "timeout": 10}

